index c06d5c759634..85961d403449 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1134,6 +1134,45 @@ static Value *foldUnsignedUnderflowCheck(ICmpInst *ZeroICmp,

   return nullptr;
 }
+/// Fold (x != -1) & (x + 1 <= y) --> x < y
+/// This handles the pattern where we check for no overflow before doing an
+/// unsigned comparison with an incremented value.
+static Value *foldICmpNEAllOnesAndICmpULEAdd(ICmpInst *NeICmp, ICmpInst *UleICmp,
+                                             bool IsAnd,
+                                             InstCombiner::BuilderTy &Builder) {
+  if (!IsAnd)
+    return nullptr;
+
+  // Match: icmp ne X, -1
+  Value *X;
+  ICmpInst::Predicate NePred;
+  const APInt *NeConst;
+  if (!match(NeICmp, m_ICmp(NePred, m_Value(X), m_APInt(NeConst))) ||
+      NePred != ICmpInst::ICMP_NE || !NeConst->isAllOnes())
+    return nullptr;
+  // Match: icmp ule (add X, 1), Y  OR  icmp ule Y, (add X, 1)
+  Value *Y;
+  ICmpInst::Predicate Pred = UleICmp->getPredicate();
+  Value *Op0 = UleICmp->getOperand(0);
+  Value *Op1 = UleICmp->getOperand(1);
+  const APInt *AddC;
+
+  if (Pred == ICmpInst::ICMP_ULE &&
+      match(Op0, m_Add(m_Specific(X), m_APInt(AddC))) &&
+      AddC->isOne()) {
+    // icmp ule (add X, 1), Y --> X < Y
+    Y = Op1;
+  } else if (Pred == ICmpInst::ICMP_UGE &&
+             match(Op1, m_Add(m_Specific(X), m_APInt(AddC))) &&
+             AddC->isOne()) {
+    // icmp uge Y, (add X, 1) --> X < Y
+    Y = Op0;
+  } else {
+    return nullptr;
+  }
+
+  return Builder.CreateICmpULT(X, Y);
+}

 struct IntPart {
   Value *From;
@@ -3106,6 +3145,13 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
     if (Value *X = foldUnsignedUnderflowCheck(RHS, LHS, IsAnd, Q, Builder))
       return X;
   }
+  // (x != -1) & (x + 1 <= y) --> x < y
+  if (!IsLogical) {
+    if (Value *X = foldICmpNEAllOnesAndICmpULEAdd(LHS, RHS, IsAnd, Builder))
+      return X;
+    if (Value *X = foldICmpNEAllOnesAndICmpULEAdd(RHS, LHS, IsAnd, Builder))
+      return X;
+  }

   if (Value *X = foldEqOfParts(LHS, RHS, IsAnd))
     return X;

