+/// This handles the pattern where we check for no overflow before doing an
+/// unsigned comparison with an incremented value.
+static Value *foldICmpNEAllOnesAndICmpULEAdd(ICmpInst *NeICmp, ICmpInst *UleICmp,
+                                             bool IsAnd,
+                                             InstCombiner::BuilderTy &Builder) {
+  if (!IsAnd)
